async function handleSendEmail(request) {
  if (request.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  const body = await request.json();
  if (!body.to || !body.subject || !body.content) {
    return new Response('Bad Request', { status: 400 });
  }

  const sendGridApiKey = await getSecret('SENDGRID_API_KEY');
  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${sendGridApiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      personalizations: [{ to: [{ email: body.to }] }],
      from: { email: 'noreply@example.com' },
      subject: body.subject,
      content: [{ type: 'text/plain', value: body.content }]
    })
  });

  if (!response.ok) {
    return new Response('Failed to send email', { status: response.status });
  }

  return new Response('Email sent successfully', { status: 200 });
}

async function handleProcessPayment(request) {
  if (request.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  const body = await request.json();
  if (!body.amount || !body.currency || !body.source) {
    return new Response('Bad Request', { status: 400 });
  }

  const stripeSecretKey = await getSecret('STRIPE_SECRET_KEY');
  const response = await fetch('https://api.stripe.com/v1/charges', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${stripeSecretKey}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: new URLSearchParams({
      amount: body.amount,
      currency: body.currency,
      source: body.source
    })
  });

  if (!response.ok) {
    return new Response('Payment processing failed', { status: response.status });
  }

  return new Response('Payment processed successfully', { status: 200 });
}

